91	    /// Render the full pack editor panel.
92	    pub fn show_pack_editor(ui: &mut egui::Ui, state: &mut PackEditorState) {
93	        ui.heading(format!("Pack Editor — {}", state.editor.pack().name));
94	
95	        // ── Category toolbar ─────────────────────────────────────────────────
96	        ui.horizontal(|ui| {
97	            ui.label("New category:");
98	            ui.text_edit_singleline(&mut state.form_new_category);
99	
100	            if ui.button("Add Category").clicked() {
101	                let name = state.form_new_category.trim().to_string();
102	                match state.editor.add_category(&name) {
103	                    Ok(()) => {
104	                        state.last_error = None;
105	                        state.form_new_category.clear();
106	                    }
107	                    Err(e) => state.last_error = Some(e.to_string()),
108	                }
109	            }
110	
111	            // Remove Category: only offered when a category is selected.
112	            if let Some(cat_name) = state.selected_category.clone() {
113	                if ui.button("Remove Category").clicked() {
114	                    match state.editor.remove_category(&cat_name) {
115	                        Ok(()) => {
116	                            state.last_error = None;
117	                            state.selected_category = None;
118	                            state.selected_macro = None;
119	                        }
120	                        Err(e) => state.last_error = Some(e.to_string()),
121	                    }
122	                }
123	
124	                // Rename Category (with two-click confirmation).
125	                if ui.button("Rename Category").clicked() {
126	                    state.show_rename_warning = true;
127	                }
128	
129	                if state.show_rename_warning {
130	                    ui.colored_label(
131	                        egui::Color32::YELLOW,
132	                        "⚠ if_flag/set_flag references are NOT updated — confirm rename?",
133	                    );
134	                    let new_name = state.form_new_category.trim().to_string();
135	                    if ui.button("Confirm Rename").clicked() && !new_name.is_empty() {
136	                        match state.editor.rename_category(&cat_name, &new_name) {
137	                            Ok(()) => {
138	                                state.last_error = None;
139	                                state.selected_category = Some(new_name.clone());
140	                                state.form_new_category.clear();
141	                                state.show_rename_warning = false;
142	                            }
143	                            Err(e) => {
144	                                state.last_error = Some(e.to_string());
145	                                state.show_rename_warning = false;
146	                            }
147	                        }
148	                    }
149	                    if ui.button("Cancel").clicked() {
150	                        state.show_rename_warning = false;
151	                    }
152	                }
153	            }
154	        });
155	
156	        ui.add_space(4.0);
157	
158	        // ── Three-column layout ───────────────────────────────────────────────
159	        // Clone lists before the egui closures to avoid simultaneous mut borrows.
160	        let category_names: Vec<String> =
161	            state.editor.pack().categories.iter().map(|c| c.name.clone()).collect();
162	
163	        let macro_names: Vec<String> = state
164	            .selected_category
165	            .as_deref()
166	            .and_then(|cat| state.editor.pack().categories.iter().find(|c| c.name == cat))
167	            .map(|cat| cat.macros.iter().map(|m| m.name.clone()).collect())
168	            .unwrap_or_default();
169	
170	        // Snapshot current macro's MacroConfig for form pre-population (read-only borrow ends here).
171	        let selected_macro_config: Option<MacroConfig> = state
172	            .selected_category
173	            .as_deref()
174	            .zip(state.selected_macro.as_deref())
175	            .and_then(|(cat, mac)| {
176	                state
177	                    .editor
178	                    .pack()
179	                    .categories
180	                    .iter()
181	                    .find(|c| c.name == cat)
182	                    .and_then(|c| c.macros.iter().find(|m| m.name == mac))
183	                    .cloned()
184	            });
185	
186	        ui.horizontal(|ui| {
187	            // ── Left: category list ─────────────────────────────────────────
188	            ui.vertical(|ui| {
189	                ui.set_min_width(140.0);
190	                ui.label("Categories");
191	                egui::ScrollArea::vertical()
192	                    .id_salt("cat_scroll")
193	                    .max_height(300.0)
194	                    .show(ui, |ui| {
195	                        for cat_name in &category_names {
196	                            let selected =
197	                                state.selected_category.as_deref() == Some(cat_name.as_str());
198	                            if ui.selectable_label(selected, cat_name.as_str()).clicked() {
199	                                if state.selected_category.as_deref() != Some(cat_name.as_str()) {
200	                                    state.selected_category = Some(cat_name.clone());
201	                                    state.selected_macro = None;
202	                                    state.pending_remove_macro = false;
203	                                }
204	                            }
205	                        }
206	                    });
207	            });
208	
209	            ui.separator();
210	
211	            // ── Middle: macro list ──────────────────────────────────────────
212	            ui.vertical(|ui| {
213	                ui.set_min_width(160.0);
214	                ui.label("Macros");
215	                egui::ScrollArea::vertical()
216	                    .id_salt("macro_scroll")
217	                    .max_height(300.0)
218	                    .show(ui, |ui| {
219	                        for mac_name in &macro_names {
220	                            let selected =
221	                                state.selected_macro.as_deref() == Some(mac_name.as_str());
222	                            if ui.selectable_label(selected, mac_name.as_str()).clicked() {
223	                                if state.selected_macro.as_deref() != Some(mac_name.as_str()) {
224	                                    state.selected_macro = Some(mac_name.clone());
225	                                    state.pending_remove_macro = false;
226	                                    // Populate form from the just-selected macro.
227	                                    if let Some(cat) = state.selected_category.as_deref() {
228	                                        if let Some(m) = state
229	                                            .editor
230	                                            .pack()
231	                                            .categories
232	                                            .iter()
233	                                            .find(|c| c.name == cat)
234	                                            .and_then(|c| {
235	                                                c.macros.iter().find(|m| m.name == *mac_name)
236	                                            })
237	                                        {
238	                                            state.form_name = m.name.clone();
239	                                            state.form_phrase =
240	                                                m.phrase.clone().unwrap_or_default();
241	                                            state.form_if_flag =
242	                                                m.if_flag.clone().unwrap_or_default();
243	                                            state.form_set_flag =
244	                                                m.set_flag.clone().unwrap_or_default();
245	                                            state.form_keys = m
246	                                                .keys
247	                                                .iter()
248	                                                .map(|k| k.key.as_str())
249	                                                .collect::<Vec<_>>()
250	                                                .join(", ");
251	                                        }
252	                                    }
253	                                }
254	                            }
255	                        }
256	                    });
257	            });
258	
259	            ui.separator();
260	
261	            // ── Right: edit form ────────────────────────────────────────────
262	            ui.vertical(|ui| {
263	                ui.set_min_width(220.0);
264	                ui.label("Edit Macro");
265	
266	                egui::Grid::new("macro_form_grid")
267	                    .num_columns(2)
268	                    .spacing([8.0, 4.0])
269	                    .show(ui, |ui| {
270	                        ui.label("Name:");
271	                        ui.text_edit_singleline(&mut state.form_name);
272	                        ui.end_row();
273	
274	                        ui.label("Phrase:");
275	                        ui.text_edit_singleline(&mut state.form_phrase);
276	                        ui.end_row();
277	
278	                        ui.label("If flag:");
279	                        ui.text_edit_singleline(&mut state.form_if_flag);
280	                        ui.end_row();
281	
282	                        ui.label("Set flag:");
283	                        ui.text_edit_singleline(&mut state.form_set_flag);
284	                        ui.end_row();
285	
286	                        ui.label("Keys:");
287	                        ui.text_edit_singleline(&mut state.form_keys);
288	                        ui.end_row();
289	                    });
290	
291	                // Per-key dwell/gap overrides (rendered for selected macro only).
292	                if let Some(ref mc) = selected_macro_config {
293	                    if !mc.keys.is_empty() {
294	                        ui.add_space(4.0);
295	                        ui.label("Key timing overrides (edit macro to apply):");
296	                        for ka in &mc.keys {
297	                            ui.horizontal(|ui| {
298	                                ui.monospace(ka.key.as_str());
299	                                ui.label(format!(
300	                                    "dwell: {} ms   gap: {} ms",
301	                                    ka.dwell_ms.map_or("default".into(), |v| v.to_string()),
302	                                    ka.gap_ms.map_or("default".into(), |v| v.to_string()),
303	                                ));
304	                            });
305	                        }
306	                    }
307	                }
308	
309	                ui.add_space(6.0);
310	
311	                // CRUD buttons.
312	                ui.horizontal(|ui| {
313	                    // Add Macro.
314	                    if ui.button("Add Macro").clicked() {
315	                        if let Some(cat) = state.selected_category.clone() {
316	                            match build_macro_config_from_form(
317	                                &state.form_name,
318	                                &state.form_phrase,
319	                                &state.form_if_flag,
320	                                &state.form_set_flag,
321	                                &state.form_keys,
322	                            ) {
323	                                Ok(mc) => match state.editor.add_macro(&cat, mc) {
324	                                    Ok(()) => state.last_error = None,
325	                                    Err(e) => state.last_error = Some(e.to_string()),
326	                                },
327	                                Err(e) => state.last_error = Some(e.to_string()),
328	                            }
329	                        } else {
330	                            state.last_error = Some("Select a category first.".into());
331	                        }
332	                    }
333	
334	                    // Update Macro.
335	                    if ui.button("Update Macro").clicked() {
336	                        match (state.selected_category.clone(), state.selected_macro.clone()) {
337	                            (Some(cat), Some(mac)) => {
338	                                match parse_key_sequence(&state.form_keys) {
339	                                    Ok(keys) => {
340	                                        let phrase = opt_from_str(&state.form_phrase);
341	                                        let if_flag = opt_from_str(&state.form_if_flag);
342	                                        let set_flag = opt_from_str(&state.form_set_flag);
343	                                        let updates = crate::pack::MacroUpdates {
344	                                            phrase: Some(phrase),
345	                                            if_flag: Some(if_flag),
346	                                            set_flag: Some(set_flag),
347	                                            sound: None,
348	                                            keys: Some(keys),
349	                                        };
350	                                        match state.editor.edit_macro(&cat, &mac, updates) {
351	                                            Ok(()) => state.last_error = None,
352	                                            Err(e) => {
353	                                                state.last_error = Some(e.to_string())
354	                                            }
355	                                        }
356	                                    }
357	                                    Err(e) => state.last_error = Some(e.to_string()),
358	                                }
359	                            }
360	                            _ => {
361	                                state.last_error =
362	                                    Some("Select a category and macro first.".into())
363	                            }
364	                        }
365	                    }
366	                });
367	
368	                // Remove Macro — two-click confirmation.
369	                ui.horizontal(|ui| {
370	                    if state.selected_macro.is_some() {
371	                        if state.pending_remove_macro {
372	                            if ui
373	                                .button(egui::RichText::new("Confirm Remove").color(egui::Color32::RED))
374	                                .clicked()
375	                            {
376	                                if let (Some(cat), Some(mac)) = (
377	                                    state.selected_category.clone(),
378	                                    state.selected_macro.clone(),
379	                                ) {
380	                                    match state.editor.remove_macro(&cat, &mac) {
381	                                        Ok(()) => {
382	                                            state.last_error = None;
383	                                            state.selected_macro = None;
384	                                            state.pending_remove_macro = false;
385	                                            state.form_name.clear();
386	                                            state.form_phrase.clear();
387	                                            state.form_if_flag.clear();
388	                                            state.form_set_flag.clear();
389	                                            state.form_keys.clear();
390	                                        }
391	                                        Err(e) => {
392	                                            state.last_error = Some(e.to_string());
393	                                            state.pending_remove_macro = false;
394	                                        }
395	                                    }
396	                                }
397	                            }
398	                            if ui.button("Cancel").clicked() {
399	                                state.pending_remove_macro = false;
400	                            }
401	                        } else if ui.button("Remove Macro").clicked() {
402	                            state.pending_remove_macro = true;
403	                        }
404	                    }
405	                });
406	            });
407	        });
408	
409	        ui.add_space(6.0);
410	
411	        // ── Save button ───────────────────────────────────────────────────────
412	        if ui.button("💾 Save Pack").clicked() {
413	            match state.save() {
414	                Ok(()) => state.last_error = None,
415	                Err(e) => state.last_error = Some(e.to_string()),
416	            }
417	        }
418	
419	        // ── Inline error display ─────────────────────────────────────────────
420	        if let Some(err) = &state.last_error.clone() {
421	            ui.colored_label(egui::Color32::RED, format!("⚠ {err}"));
422	        }
423	    }
