425	    /// Convert a form string to `Some(s)` when non-empty, `None` to clear the field.
426	    /// Used by Update Macro to produce `Some(None)` (clear) vs `Some(Some(s))` (set).
427	    fn opt_from_str(s: &str) -> Option<String> {
428	        let trimmed = s.trim();
429	        if trimmed.is_empty() { None } else { Some(trimmed.to_string()) }
430	    }
431	}
