438	/// Errors returned by [`build_macro_config_from_form`].
439	#[derive(Debug)]
440	pub enum FormBuildError {
441	    EmptyName,
442	    KeyParseError(anyhow::Error),
443	}
444	
445	impl std::fmt::Display for FormBuildError {
446	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
447	        match self {
448	            FormBuildError::EmptyName => write!(f, "macro name must not be empty"),
449	            FormBuildError::KeyParseError(e) => write!(f, "key parse error: {e}"),
450	        }
451	    }
452	}
453	
454	impl std::error::Error for FormBuildError {}
