521	    #[test]
522	    fn parse_key_sequence_single() {
523	        let result = parse_key_sequence("KEY_W").unwrap();
524	        assert_eq!(result.len(), 1);
525	        assert_eq!(result[0].key, "KEY_W");
526	        assert!(result[0].dwell_ms.is_none());
527	        assert!(result[0].gap_ms.is_none());
528	    }
