use eframe::egui;
use rfd::FileDialog;
use tracing;

use crate::config::MacroConfig;
use crate::control::client::send_command;
use crate::control::protocol::ControlRequest;
use crate::pack::{get_profiles_dir, Pack, PackEditor};

